import type { BookPage } from '@/types'

const CHAPTER_LINE = /^\s*(?:#+\s+|Kapitel\s+\d+[:.\s-]*|Chapter\s+\d+[:.\s-]*)\s*(.+)$/i

/**
 * Parse a raw text or markdown block into chapters/pages.
 *
 * Rules:
 *  - A line starting with one-or-more `#`, or starting with "Kapitel N" /
 *    "Chapter N", introduces a new chapter. Whatever is left on that line
 *    becomes the chapter title.
 *  - All following lines (until the next chapter line) are joined into the
 *    chapter text.
 *  - Chapters are numbered sequentially as pages starting at 1.
 *  - If the input contains no detectable chapter lines, a single page is
 *    returned with the whole input as text and a default title.
 */
export function detectChapters(raw: string, fallbackTitle = 'Seite 1'): BookPage[] {
  const lines = raw.replace(/\r\n/g, '\n').split('\n')
  const pages: BookPage[] = []
  let current: BookPage | null = null
  let page = 0

  for (const line of lines) {
    const match = CHAPTER_LINE.exec(line)
    if (match) {
      if (current) pages.push(finalize(current))
      page += 1
      current = { page, title: match[1]!.trim() || `Seite ${page}`, text: '' }
    } else if (current) {
      current.text += (current.text ? '\n' : '') + line
    } else {
      // Lines before any chapter heading → stash into a "page 1" implicit chapter.
      page = 1
      current = { page, title: fallbackTitle, text: line }
    }
  }
  if (current) pages.push(finalize(current))
  return pages.length ? pages : [{ page: 1, title: fallbackTitle, text: raw.trim() }]
}

function finalize(p: BookPage): BookPage {
  return { ...p, text: p.text.trim() }
}

/**
 * Returns `true` if the given single line introduces a chapter.
 * Used by the TipTap editor to render the chapter icon decoration.
 */
export function isChapterLine(line: string): boolean {
  return CHAPTER_LINE.test(line)
}
